package router

import (
	"net/http"
	"strings"
)

type route struct {
	path    string
	handler http.HandlerFunc
}

type Router struct {
	routes []route
}

func normalizePath(p string) string {
	if p != "/" {
		p = strings.TrimRight(p, "/")
	}
	return p
}

func New() *Router {
	return &Router{}
}

func (r *Router) Handle(path string, h http.HandlerFunc) {
	r.routes = append(r.routes, route{path: normalizePath(path), handler: h})
}

func (r *Router) ServeHTTP(w http.ResponseWriter, req *http.Request) {
	reqPath := normalizePath(req.URL.Path)
	for _, rt := range r.routes {
		if reqPath == rt.path {
			rt.handler(w, req)
			return
		}
	}
	http.NotFound(w, req)
}
